<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Vibrant Kanban Board</title>
    <!-- Tailwind CSS via CDN -->
    <script src="https://cdn.tailwindcss.com"></script>
    <!-- Custom Styles for Transitions and Confetti -->
    <style>
        /* Base variables for theming */
        :root {
            --col-backlog: #e5e7eb; /* gray-200 */
            --col-in-progress: #dbeafe; /* blue-100 */
            --col-review: #fef3c7; /* amber-100 */
            --col-done: #d1fae5; /* emerald-100 */
        }

        body {
            font-family: 'Inter', sans-serif;
            background-color: #f3f4f6; /* gray-100 */
        }

        /* Column Styling with Transitions */
        .kanban-column {
            background-color: white;
            border-radius: 0.75rem;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
            padding: 1rem;
            transition: all 0.3s ease;
        }

        /* Card Styling */
        .kanban-card {
            background-color: white;
            border-radius: 0.5rem;
            padding: 1rem;
            margin-bottom: 0.75rem;
            box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px 0 rgba(0, 0, 0, 0.06);
            cursor: grab;
            transition: all 0.2s ease-in-out;
            animation: fadeIn 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }

        .kanban-card:active {
            cursor: grabbing;
        }

        /* Dragging State */
        .kanban-card.dragging {
            opacity: 0.5;
            transform: scale(0.95);
        }

        /* Drag Over/Focus State */
        .kanban-card:focus-within {
            border: 2px solid #3b82f6; /* blue-500 */
            transform: scale(1.02);
        }

        /* Animations */
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(10px); }
